import{_ as n,W as g,X as t,Z as i,$ as a,a0 as o,Y as l,a1 as d,D as c}from"./framework-c9619a7b.js";const p={},m=i("h1",{id:"使用方法",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#使用方法","aria-hidden":"true"},"#"),a(" 使用方法")],-1),r={href:"https://zhuanlan.zhihu.com/p/373636790",target:"_blank",rel:"noopener noreferrer"},s=i("h2",{id:"基础使用",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#基础使用","aria-hidden":"true"},"#"),a(" 基础使用")],-1),b=i("ol",null,[i("li",null,[a('"插入>公式" '),i("img",{src:"https://minio.kevin2li.top/image-bed/vanblog/img/8654f87e7a52c5adfe01a710647d75b0.image.png",alt:"image.png",loading:"lazy"})])],-1),f=i("p",null,[a(':::tip{title="提示"} 也可以用快捷键'),i("code",null,"Alt+="),a('直接插入公式 ::: 2. 选择"Latex"公式 '),i("img",{src:"https://minio.kevin2li.top/image-bed/vanblog/img/001a6fca4e501d29fd2e67749cd0c427.image.png",alt:"image.png",loading:"lazy"})],-1),h=d('<ol start="3"><li>编写Latex公式</li></ol><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/9287cbb9e1fa65994113ee05cbcc7222.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>在公式最后回车即可，效果如下：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/6401df85b758bde7a94b8657ab04c9a8.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h2 id="进阶" tabindex="-1"><a class="header-anchor" href="#进阶" aria-hidden="true">#</a> 进阶</h2><h3 id="公式编号" tabindex="-1"><a class="header-anchor" href="#公式编号" aria-hidden="true">#</a> 公式编号</h3><p>在公式最后添加<code>#编号</code></p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/7a5665ef25e5039791c34e93f6565d9f.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>效果如下：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/c46c04edc39b324738c95bd3a2dec777.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h3 id="编号-1-1-的短线太长" tabindex="-1"><a class="header-anchor" href="#编号-1-1-的短线太长" aria-hidden="true">#</a> 编号(1-1)的短线太长</h3><p>当使用(1-1)这样的编号时，短线可能会被识别为减号，导致显示过长。</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/0987d09cf5f403d6a471b1ac97cb5467.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>此时可以加引号转义：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/bee94b909b23f06e3ebe1f957599aa3c.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>效果如下：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/34887c3979b765cb2eeab59603fb605a.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h3 id="公式对齐" tabindex="-1"><a class="header-anchor" href="#公式对齐" aria-hidden="true">#</a> 公式对齐</h3><p>默认的公式插入，只能实现居中对齐，如果需要其他对齐方式可以借助制表位实现。</p><ol><li>打开“段落”,选择“制表位” :::tip{title=&quot;提示&quot;} 也可以用快捷键<code>Alt+O+P</code>直接打开段落 :::</li></ol><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/88c7818a3f98d521e836c3df9e1d01c4.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><ol start="2"><li>设置制表位</li></ol><ul><li><p>在20字符位置，添加“居中对齐”的制表位 <img src="https://minio.kevin2li.top/image-bed/vanblog/img/4c5072f7461675c75d1e1d65cd71cba4.image.png" alt="image.png" loading="lazy"></p></li><li><p>在40字符位置，添加“右对齐”的制表位 <img src="https://minio.kevin2li.top/image-bed/vanblog/img/1bb47d4d90e75b0acd21e78aec22dda3.image.png" alt="image.png" loading="lazy"></p></li></ul>',23);function u(_,v){const e=c("ExternalLinkIcon");return g(),t("div",null,[m,i("blockquote",null,[i("p",null,[a("参考："),i("a",r,[a("https://zhuanlan.zhihu.com/p/373636790"),o(e)])])]),s,b,f,l(" more "),h])}const k=n(p,[["render",u],["__file","Word插入LaTex公式.html.vue"]]);export{k as default};
